class Solution:
    def mostPopularCreator(self, creators, ids, views):
        pop = {}
        best = {}
        for c, i, v in zip(creators, ids, views):
            pop[c] = pop.get(c, 0) + v
            if c not in best or v > best[c][0] or (v == best[c][0] and i < best[c][1]):
                best[c] = (v, i)
        top = max(pop.values())
        res = []
        for c in pop:
            if pop[c] == top:
                res.append([c, best[c][1]])
        res.sort()
        return res

