class Solution:
    def mostPopularCreator(self, creators, ids, views):
        from collections import defaultdict
        total = defaultdict(int)
        top_view = {}
        top_id = {}
        for c, i, v in zip(creators, ids, views):
            total[c] += v
            if c not in top_view or v > top_view[c] or (v == top_view[c] and i < top_id[c]):
                top_view[c] = v
                top_id[c] = i
        best = max(total.values())
        ans = [[c, top_id[c]] for c in total if total[c] == best]
        ans.sort()
        return ans

