var mostPopularCreator = function(creators, ids, views) {
    const total = new Map();
    const topView = new Map();
    const topId = new Map();
    for (let k = 0; k < creators.length; k++) {
        const c = creators[k], i = ids[k], v = views[k];
        total.set(c, (total.get(c) || 0) + v);
        if (!topView.has(c) || v > topView.get(c) || (v === topView.get(c) && i < topId.get(c))) {
            topView.set(c, v);
            topId.set(c, i);
        }
    }
    let best = -Infinity;
    for (const t of total.values()) best = Math.max(best, t);
    const ans = [];
    for (const [c, t] of total) {
        if (t === best) ans.push([c, topId.get(c)]);
    }
    ans.sort((a, b) => (a[0] < b[0] ? -1 : a[0] > b[0] ? 1 : (a[1] < b[1] ? -1 : a[1] > b[1] ? 1 : 0)));
    return ans;
};
